class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private lateinit var bridgeInterface: WebAppBridge
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoPath: String? = null
    
    private val allowedOrigins = setOf(
        "https://yourdomain.com",
        "https://www.yourdomain.com",
        "https://app.yourdomain.com"
    )
    
    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (filePathCallback == null) return@registerForActivityResult
        
        val results = if (result.resultCode == Activity.RESULT_OK) {
            val data = result.data
            if (data?.data != null) {
                arrayOf(data.data!!)
            } else {
                cameraPhotoPath?.let { path ->
                    arrayOf(Uri.parse(path))
                }
            }
        } else {
            null
        }
        
        filePathCallback?.onReceiveValue(results)
        filePathCallback = null
    }
    
    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            bridgeInterface.onPermissionResult("camera", true)
        } else {
            bridgeInterface.onPermissionResult("camera", false)
        }
    }
    
    private val notificationPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            bridgeInterface.onPermissionResult("notification", true)
        } else {
            bridgeInterface.onPermissionResult("notification", false)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        
        webView = findViewById(R.id.webView)
        bridgeInterface = WebAppBridge(this, webView)
        
        setupWebView()
        loadWebApp()
    }
    
    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = false
            allowContentAccess = true
            allowFileAccessFromFileURLs = false
            allowUniversalAccessFromFileURLs = false
            mediaPlaybackRequiresUserGesture = false
        }
        
        webView.addJavascriptInterface(bridgeInterface, "NativeBridge")
        
        webView.webViewClient = object : WebViewClient() {
            override fun shouldInterceptRequest(
                view: WebView?,
                request: WebResourceRequest?
            ): WebResourceResponse? {
                request?.url?.let { uri ->
                    if (!isAllowedOrigin(uri.toString())) {
                        return WebResourceResponse("text/plain", "UTF-8", null)
                    }
                }
                return super.shouldInterceptRequest(view, request)
            }
            
            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                val url = request?.url?.toString() ?: return false
                
                if (isAllowedOrigin(url)) {
                    return false
                }
                
                val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                startActivity(intent)
                return true
            }
        }
        
        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@MainActivity.filePathCallback?.onReceiveValue(null)
                this@MainActivity.filePathCallback = filePathCallback
                
                val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                if (takePictureIntent.resolveActivity(packageManager) != null) {
                    val photoFile: File? = try {
                        createImageFile()
                    } catch (ex: IOException) {
                        null
                    }
                    
                    photoFile?.also {
                        val photoURI: Uri = FileProvider.getUriForFile(
                            this@MainActivity,
                            "${applicationContext.packageName}.fileprovider",
                            it
                        )
                        cameraPhotoPath = photoURI.toString()
                        takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI)
                    }
                }
                
                val contentSelectionIntent = Intent(Intent.ACTION_GET_CONTENT)
                contentSelectionIntent.addCategory(Intent.CATEGORY_OPENABLE)
                contentSelectionIntent.type = "image/*"
                
                val intentArray = arrayOf(takePictureIntent)
                
                val chooserIntent = Intent(Intent.ACTION_CHOOSER)
                chooserIntent.putExtra(Intent.EXTRA_INTENT, contentSelectionIntent)
                chooserIntent.putExtra(Intent.EXTRA_TITLE, "Select Image")
                chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray)
                
                fileChooserLauncher.launch(chooserIntent)
                return true
            }
        }
    }
    
    private fun createImageFile(): File {
        val timeStamp: String = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir: File = getExternalFilesDir(null)!!
        return File.createTempFile(
            "JPEG_${timeStamp}_",
            ".jpg",
            storageDir
        )
    }
    
    private fun isAllowedOrigin(url: String): Boolean {
        return allowedOrigins.any { url.startsWith(it) }
    }
    
    private fun loadWebApp() {
        webView.loadUrl("https://yourdomain.com")
    }
    
    fun requestCameraPermission() {
        when {
            ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED -> {
                bridgeInterface.onPermissionResult("camera", true)
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }
    
    fun requestNotificationPermission() {
        if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            when {
                ContextCompat.checkSelfPermission(
                    this,
                    Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED -> {
                    bridgeInterface.onPermissionResult("notification", true)
                }
                else -> {
                    notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        } else {
            bridgeInterface.onPermissionResult("notification", true)
        }
    }
    
    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }
}

class WebAppBridge(
    private val activity: MainActivity,
    private val webView: WebView
) {
    private val localStorage = LocalStorageManager(activity)
    private val allowedMethods = setOf(
        "requestCameraAccess",
        "capturePhoto",
        "saveToLocalStorage",
        "getFromLocalStorage",
        "removeFromLocalStorage",
        "clearLocalStorage",
        "registerPushNotifications",
        "getPushToken"
    )
    
    @JavascriptInterface
    fun invoke(method: String, paramsJson: String): String {
        if (!allowedMethods.contains(method)) {
            return createErrorResponse("Method not allowed")
        }
        
        return try {
            val params = JSONObject(paramsJson)
            when (method) {
                "requestCameraAccess" -> requestCameraAccess()
                "capturePhoto" -> capturePhoto()
                "saveToLocalStorage" -> saveToLocalStorage(params)
                "getFromLocalStorage" -> getFromLocalStorage(params)
                "removeFromLocalStorage" -> removeFromLocalStorage(params)
                "clearLocalStorage" -> clearLocalStorage()
                "registerPushNotifications" -> registerPushNotifications()
                "getPushToken" -> getPushToken()
                else -> createErrorResponse("Unknown method")
            }
        } catch (e: Exception) {
            createErrorResponse("Invalid request: ${e.message}")
        }
    }
    
    private fun requestCameraAccess(): String {
        activity.runOnUiThread {
            activity.requestCameraPermission()
        }
        return createSuccessResponse(JSONObject().apply {
            put("message", "Permission request initiated")
        })
    }
    
    private fun capturePhoto(): String {
        val hasCameraPermission = ContextCompat.checkSelfPermission(
            activity,
            Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
        
        if (!hasCameraPermission) {
            return createErrorResponse("Camera permission not granted")
        }
        
        activity.runOnUiThread {
            val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
            if (takePictureIntent.resolveActivity(activity.packageManager) != null) {
                activity.startActivity(takePictureIntent)
            }
        }
        
        return createSuccessResponse(JSONObject().apply {
            put("message", "Camera launched")
        })
    }
    
    private fun saveToLocalStorage(params: JSONObject): String {
        val key = params.optString("key", "")
        val value = params.optString("value", "")
        
        if (key.isEmpty()) {
            return createErrorResponse("Key is required")
        }
        
        if (!isValidStorageKey(key)) {
            return createErrorResponse("Invalid key format")
        }
        
        localStorage.save(key, value)
        return createSuccessResponse(JSONObject().apply {
            put("message", "Data saved successfully")
        })
    }
    
    private fun getFromLocalStorage(params: JSONObject): String {
        val key = params.optString("key", "")
        
        if (key.isEmpty()) {
            return createErrorResponse("Key is required")
        }
        
        if (!isValidStorageKey(key)) {
            return createErrorResponse("Invalid key format")
        }
        
        val value = localStorage.get(key)
        return createSuccessResponse(JSONObject().apply {
            put("value", value ?: "")
        })
    }
    
    private fun removeFromLocalStorage(params: JSONObject): String {
        val key = params.optString("key", "")
        
        if (key.isEmpty()) {
            return createErrorResponse("Key is required")
        }
        
        if (!isValidStorageKey(key)) {
            return createErrorResponse("Invalid key format")
        }
        
        localStorage.remove(key)
        return createSuccessResponse(JSONObject().apply {
            put("message", "Data removed successfully")
        })
    }
    
    private fun clearLocalStorage(): String {
        localStorage.clear()
        return createSuccessResponse(JSONObject().apply {
            put("message", "Storage cleared successfully")
        })
    }
    
    private fun registerPushNotifications(): String {
        activity.runOnUiThread {
            activity.requestNotificationPermission()
        }
        return createSuccessResponse(JSONObject().apply {
            put("message", "Notification permission request initiated")
        })
    }
    
    private fun getPushToken(): String {
        var token = ""
        FirebaseMessaging.getInstance().token.addOnCompleteListener(OnCompleteListener { task ->
            if (!task.isSuccessful) {
                return@OnCompleteListener
            }
            token = task.result
            
            activity.runOnUiThread {
                webView.evaluateJavascript(
                    "window.onPushTokenReceived && window.onPushTokenReceived('$token')",
                    null
                )
            }
        })
        
        return createSuccessResponse(JSONObject().apply {
            put("message", "Token request initiated")
        })
    }
    
    fun onPermissionResult(permission: String, granted: Boolean) {
        activity.runOnUiThread {
            webView.evaluateJavascript(
                "window.onPermissionResult && window.onPermissionResult('$permission', $granted)",
                null
            )
        }
    }
    
    private fun isValidStorageKey(key: String): Boolean {
        return key.matches(Regex("^[a-zA-Z0-9_.-]{1,100}$"))
    }
    
    private fun createSuccessResponse(data: JSONObject): String {
        return JSONObject().apply {
            put("success", true)
            put("data", data)
        }.toString()
    }
    
    private fun createErrorResponse(message: String): String {
        return JSONObject().apply {
            put("success", false)
            put("error", message)
        }.toString()
    }
}

class LocalStorageManager(context: Context) {
    private val sharedPreferences = context.getSharedPreferences(
        "WebAppStorage",
        Context.MODE_PRIVATE
    )
    
    fun save(key: String, value: String) {
        sharedPreferences.edit().putString(key, value).apply()
    }
    
    fun get(key: String): String? {
        return sharedPreferences.getString(key, null)
    }
    
    fun remove(key: String) {
        sharedPreferences.edit().remove(key).apply()
    }
    
    fun clear() {
        sharedPreferences.edit().clear().apply()
    }
}